def _responses_map_for(endpoint: str, method: str) -> Dict[str, Any]:
    """
    Returns the responses mapping from the API spec for an endpoint-method combination.
    """
    if _VALIDATOR is None:
        return {}
    paths = _VALIDATOR.spec.get("paths", {})
    op = (paths.get(endpoint) or {}).get(method.lower()) or {}
    return op.get("responses") or {}

def _choose_response_key_for_status(endpoint: str, method: str, actual_status: int) -> Optional[str]:
    """
    Chooses the proper response key for schema validation:
    - If exact status code exists in spec responses, use it (e.g., "201")
    - Else if "default" exists, use "default"
    - Else returns None (no schema validation possible)
    """
    responses = _responses_map_for(endpoint, method)
    if not responses:
        return None
    key = str(actual_status)
    if key in responses:
        return key
    if "default" in responses:
        return "default"
    return None

def _validate_response_schema(endpoint: str, method: str, status_key: str, response: Response) -> Dict[str, Any]:
    """
    Delegates to SwaggerSchemaValidator.validate_schema_by_response with appropriate inputs.
    """
    assert _VALIDATOR is not None, "Validator must be initialized before calling this function."
    result = _VALIDATOR.validate_schema_by_response(endpoint, method, status_key, response)
    return result


