@pytest.mark.smoke
@pytest.mark.parametrize("scenario_case", _PARAM_CASES, ids=_PARAM_IDS)
def test_create_organization_post_smoke_required_fields(
    api_client,
    org_endpoint: str,
    default_headers: Dict[str, str],
    request_auth_params: Dict[str, str],
    request_payload_factory,
    scenario_case: Dict[str, Any],
):
    """
    Smoke test: Create organization (POST /organization) using only REQUIRED fields in request body.
    - Validates response status code and schema per OpenAPI specification
    - Applies table-driven scenarios from organization.json
    - Uses config_test_data values when scenario does not include required fields
    - This test intentionally excludes authentication permutations (handled separately)
    """
    # Ensure validator is available
    if _VALIDATOR is None:
        pytest.skip(_VALIDATOR_INIT_ERROR or "Validator not initialized")

    # Build required-only request payload
    payload = request_payload_factory(scenario_case)

    # If any required field is missing and cannot be sourced from config, skip to avoid invalid request construction
    missing_fields: List[str] = []
    for req in ("name", "vcs_type"):
        if req not in payload or payload[req] in (None, ""):
            missing_fields.append(req)
    if missing_fields:
        pytest.skip(f"Missing required request fields {missing_fields}; provide via organization.json or config.yml test_data.")

    # Attempt request
    response: Response = api_client.post(
        org_endpoint,
        headers=default_headers,
        params=request_auth_params or None,
        json=payload,
    )

    # Expected status may be defined in scenario; do not hardcode
    expected_status = scenario_case.get("statusCode")
    if isinstance(expected_status, int):
        assert response.status_code in (expected_status, *range(200, 300)), (
            f"Unexpected status: got {response.status_code}, expected {expected_status} or another 2xx."
        )

    # Determine which response schema key to use for validation
    status_key = _choose_response_key_for_status(org_endpoint, "POST", response.status_code)

    # If default is present in spec and a non-2xx occurred, assert it is indeed non-2xx as a guardrail
    if status_key == "default":
        assert not (200 <= response.status_code < 300), (
            f"Spec 'default' should not validate 2xx. Received {response.status_code}"
        )

    # Validate response schema if available
    if status_key is not None:
        result = _validate_response_schema(org_endpoint, "POST", status_key, response)
        assert result.get("valid") is True, f"Schema validation failed: {result}"
    else:
        # If the spec doesn't define this status and no 'default', we still assert presence of a plausible status code range
        assert response.status_code in (*range(200, 300), *range(400, 600)), (
            f"Status {response.status_code} not covered by spec and no default provided."
        )


